class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        vector<long long> dp(n + 1, 0);
        long long gcd = nums[0];
        for (int i = 1; i < n; i++) {
            gcd = __gcd(gcd, nums[i]);
        }
        dp[0] = gcd;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                dp[i] = max(dp[i], dp[j] * (i - j) * gcd);
                if (k > 0 && i - j > 1) {
                    dp[i] = max(dp[i], dp[j] * (i - j) * __gcd(gcd, nums[j]));
                    k--;
                }
            }
        }
        return dp[n];
    }
};
```

